let view = "home";
let index = 0;
let currentCat = "all";
let searchText = "";

const screen = document.getElementById("screen");
const saved = JSON.parse(localStorage.getItem("FrenchLearning_v42") || "{}");
const state = {
  total: saved.total || 0,
  correct: saved.correct || 0,
  fav: saved.fav || [],
  weak: saved.weak || [],
  history: saved.history || []
};

function save(){localStorage.setItem("FrenchLearning_v42", JSON.stringify(state));}
function rate(){return state.total ? Math.round(state.correct/state.total*100) : 0;}
function setActive(v){document.querySelectorAll(".nav-btn").forEach(b=>b.classList.toggle("active",b.dataset.view===v));}
function go(v){view=v;setActive(v);render();}
function cats(){return [...new Set(questions.map(q=>q.cat))];}

function list(){
  let arr = currentCat==="all" ? questions : questions.filter(q=>q.cat===currentCat);
  if(searchText.trim()){
    const s = searchText.trim().toLowerCase();
    arr = arr.filter(q => (q.q+" "+q.a+" "+q.cat+" "+q.st+" "+q.explanation).toLowerCase().includes(s));
  }
  return arr;
}

function render(){
  if(view==="home") renderHome();
  if(view==="grammar") renderGrammar();
  if(view==="quiz") renderQuiz();
  if(view==="cats") renderCats();
  if(view==="search") renderSearch();
  if(view==="record") renderRecord();
}

function renderHome(){
  screen.innerHTML = `
    <div class="grid home-grid">
      <button class="tile" onclick="go('grammar')">📖 文法カード<small>${grammarCards.length}項目 / 強化版</small></button>
      <button class="tile" onclick="startAll()">📝 全問<small>${questions.length}問</small></button>
      <button class="tile" onclick="startPremium()">💎 Premium<small>丁寧な問題</small></button>
      <button class="tile" onclick="go('cats')">📚 分類別<small>${cats().length}カテゴリ</small></button>
      <button class="tile" onclick="go('search')">🔍 検索<small>動詞・構文で探す</small></button>
      <div class="tile">📊 正答率<small>${rate()}%</small></div>
    </div>

    <section class="card">
      <div class="badges"><span class="badge hot">v${VERSION}</span><span class="badge">問題修正版</span></div>
      <div class="fr">${questions.length}問はそのまま</div>
      <div class="jp">問題側にも「英語なら」を追加。活用問題は同じ主語・同じ動詞の4択に修正。問いも日本語ベースに統一。</div>
      <div class="exp judgment"><strong>今回の追加</strong><br>🇯🇵 日本語 / 🇬🇧 英語なら / 🧩 構文（日本語つき） / 💡 出るたび判断 / ⚠️ よくあるミス / 📝 例文 / 🇯🇵 訳 / 🎯 関連問題へ</div>
    </section>
  `;
}

function renderGrammar(){
  screen.innerHTML = `
    <section class="card">
      <div class="badges"><span class="badge hot">文法カード</span><span class="badge">${grammarCards.length}項目</span></div>
      <div class="fr">構文辞典</div>
      <div class="jp">見た瞬間に「何を判断するか」まで確認できる形。</div>
      <input class="search" id="grammarSearch" placeholder="文法カード検索：pour / 接続法 / because" oninput="renderGrammarList(this.value)" />
      <div id="grammarList" class="grammar-grid" style="margin-top:14px"></div>
    </section>`;
  renderGrammarList("");
}

function renderGrammarList(query){
  const box = document.getElementById("grammarList");
  if(!box) return;
  const s = String(query || "").toLowerCase();
  const arr = grammarCards.filter(c => (c.term+" "+c.jp+" "+c.en+" "+c.structure_fr+" "+c.judgment).toLowerCase().includes(s));
  box.innerHTML = arr.map((c,i) => {
    const realIndex = grammarCards.indexOf(c);
    return `<button class="pill-card" onclick="showGrammar(${realIndex})">
      <strong>${safe(c.term)}</strong><br>
      <small>${safe(c.jp)} / ${safe(c.en)}<br>💡 ${safe(c.judgment)}</small>
    </button>`;
  }).join("");
}

function showGrammar(i){
  const c = grammarCards[i];
  const related = (c.related || []).map(id => {
    const q = questions.find(x => x.id === id);
    if(!q) return "";
    return `<button class="related-btn" onclick="openQuestionById(${id})">Ex.${q.ex}-${q.num}</button>`;
  }).join("");

  screen.innerHTML = `
    <section class="card">
      <div class="badges">
        <span class="badge hot">${safe(c.term)}</span>
        <span class="badge">頻度 <span class="freq">${safe(c.freq)}</span></span>
      </div>

      <div class="fr">🇫🇷 ${safe(c.term)}</div>

      <div class="exp">
        <div class="mini-label">🇯🇵 日本語</div>
        <div class="big-jp">${safe(c.jp)}</div>
      </div>

      <div class="exp">
        <div class="mini-label">🇬🇧 英語なら</div>
        <strong>${safe(c.en)}</strong>
        <br><br>${safe(c.eng_diff)}
      </div>

      <div class="exp">
        <div class="mini-label">🧩 構文</div>
        <strong>${safe(c.structure_fr)}</strong>
        <br>🇯🇵 ${safe(c.structure_jp)}
      </div>

      <div class="exp judgment">
        <div class="mini-label">💡 出るたび判断</div>
        <strong>${safe(c.judgment)}</strong>
      </div>

      <div class="exp warning">
        <div class="mini-label">⚠️ よくあるミス</div>
        ${safe(c.mistake)}
      </div>

      <div class="exp example-box">
        <div class="mini-label">📝 例文</div>
        <strong>${safe(c.example)}</strong>
        <br><br><div class="mini-label">📝 日本語訳</div>
        ${safe(c.translation)}
      </div>

      <div class="exp">
        <div class="mini-label">🟢 覚えるコツ</div>
        ${safe(c.tip)}
      </div>

      <div class="exp">
        <div class="mini-label">🎓 試験ポイント</div>
        ${safe(c.exam)}
      </div>

      <div class="exp">
        <div class="mini-label">🎯 関連問題へ</div>
        <div class="related-wrap">${related || "関連問題は検索から確認してください。"}</div>
      </div>

      <div class="row"><button onclick="renderGrammar()">戻る</button><button onclick="go('quiz')">問題へ</button></div>
    </section>`;
}

function openQuestionById(id){
  currentCat = "all";
  searchText = "";
  const pos = questions.findIndex(q => q.id === id);
  index = pos >= 0 ? pos : 0;
  go("quiz");
}

function startPremium(){
  currentCat = "Premium接続法";
  searchText = "";
  index = 0;
  go("quiz");
}

function startAll(){
  currentCat="all";
  searchText="";
  index=0;
  questions.sort(()=>Math.random()-.5);
  go("quiz");
}

function renderCats(){
  const rows = cats().map(cat => {
    const count = questions.filter(q=>q.cat===cat).length;
    return `<button class="pill-card" onclick="startCat('${esc(cat)}')"><strong>${safe(cat)}</strong><br><small>${count}問</small></button>`;
  }).join("");
  screen.innerHTML = `
    <section class="card">
      <div class="badges"><span class="badge hot">分類</span><span class="badge">${questions.length}問</span></div>
      <div class="fr">カテゴリ別に練習</div>
      <div class="unit-list">${rows}</div>
    </section>`;
}

function startCat(cat){currentCat=cat;searchText="";index=0;go("quiz");}

function renderSearch(){
  const arr = list();
  screen.innerHTML = `
    <section class="card">
      <div class="badges"><span class="badge hot">検索</span><span class="badge">${arr.length}件</span></div>
      <input class="search" id="searchBox" value="${safe(searchText)}" placeholder="例：venir / 接続法 / pour que" oninput="doSearch(this.value)" />
      <div class="unit-list" style="margin-top:14px">
        ${arr.slice(0,80).map(q=>`<button class="pill-card" onclick="openFromSearch(${q.id})"><strong>${safe(q.cat)}</strong><br><small>${safe(q.q)} / 答え: ${safe(q.a)}</small></button>`).join("")}
      </div>
    </section>`;
  const box=document.getElementById("searchBox"); if(box) box.focus();
}

function doSearch(v){searchText=v;renderSearch();}
function openFromSearch(id){currentCat="all";searchText="";const pos=questions.findIndex(q=>q.id===id);index=pos>=0?pos:0;go("quiz");}

function renderQuiz(){
  const arr = list();
  if(!arr.length){screen.innerHTML="<section class='card'>問題がありません。</section>";return;}
  if(index>=arr.length) index=0;
  const q=arr[index];
  screen.innerHTML = `
    <section class="card">
      <div class="badges">
        <span class="badge">${safe(q.cat)}</span>
        <span class="badge">Ex.${q.ex}-${q.num}</span>
        <span class="badge hot">${index+1}/${arr.length}</span>
      </div>
      <div class="progress"><div class="progress-bar" style="width:${(index+1)/arr.length*100}%"></div></div>
      <div class="fr">${safe(q.q).replace("____","<span class='blank'></span>")}</div>
      <div class="jp">🇯🇵 ${safe(q.jp)}</div>
      <div class="choice-list">
        ${q.choices.map(ch=>`<button class="choice" onclick="checkChoice(this, '${esc(ch)}')">${safe(ch)}</button>`).join("")}
      </div>
      <div class="row">
        <button onclick="prevQ()">前へ</button>
        <button onclick="showAnswer()">解説</button>
        <button onclick="nextQ()">次へ</button>
      </div>
      <div class="row">
        <button onclick="fav()">⭐ 保存</button>
        <button onclick="weak()">⚠️ 苦手</button>
      </div>
      <div id="answerBox" class="answer">
        <div class="exp"><strong>🇫🇷 正解</strong><br>${safe(q.full)}</div>
        <div class="exp eng-box"><strong>🇬🇧 英語なら</strong><br>${safe(q.english || "English: check the closest English structure in the grammar card.")}</div>
        <div class="exp"><strong>🧩 構文</strong><br>${safe(q.st)}</div>
        <div class="exp"><strong>Pourquoi ?</strong><br>${safe(q.explanation)}</div>
        <div class="exp"><strong>出典</strong><br>Exercice plus ${q.ex} - ${q.num}</div>
      </div>
    </section>`;
}

function checkChoice(el,val){
  const q=list()[index];
  state.total++;
  document.querySelectorAll(".choice").forEach(b=>{if(b.textContent===q.a)b.classList.add("correct");});
  if(val===q.a){state.correct++;el.classList.add("correct");}else{el.classList.add("wrong");if(!state.weak.includes(q.id))state.weak.push(q.id);}
  state.history.unshift(q.id);state.history=[...new Set(state.history)].slice(0,60);
  save();showAnswer();
}

function showAnswer(){const box=document.getElementById("answerBox");if(box)box.classList.add("show");}
function nextQ(){index=(index+1)%list().length;renderQuiz();}
function prevQ(){index=(index-1+list().length)%list().length;renderQuiz();}
function fav(){const q=list()[index];if(!state.fav.includes(q.id))state.fav.push(q.id);save();alert("お気に入りに保存しました");}
function weak(){const q=list()[index];if(!state.weak.includes(q.id))state.weak.push(q.id);save();alert("苦手に追加しました");}

function renderRecord(){
  const favs=questions.filter(q=>state.fav.includes(q.id));
  const weaks=questions.filter(q=>state.weak.includes(q.id));
  screen.innerHTML=`
    <section class="card">
      <div class="badges"><span class="badge hot">記録</span><span class="badge">v${VERSION}</span></div>
      <div class="fr">学習記録</div>
      <div class="exp">解答数：${state.total}<br>正解数：${state.correct}<br>正答率：${rate()}%<br>お気に入り：${favs.length}問<br>苦手：${weaks.length}問</div>
      <div class="section-title">⭐ お気に入り</div>
      ${favs.length?favs.slice(0,60).map(q=>`<div class="exp"><strong>${safe(q.cat)}</strong><br>${safe(q.q)}<br>答え：${safe(q.a)}</div>`).join(""):"<div class='jp'>まだありません。</div>"}
      <div class="section-title">⚠️ 苦手</div>
      ${weaks.length?weaks.slice(0,60).map(q=>`<div class="exp"><strong>${safe(q.cat)}</strong><br>${safe(q.q)}<br>答え：${safe(q.a)}</div>`).join(""):"<div class='jp'>まだありません。</div>"}
    </section>`;
}

function safe(s){return String(s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));}
function esc(s){return String(s).replace(/\\/g,"\\\\").replace(/'/g,"\\'");}

document.querySelectorAll(".nav-btn").forEach(b=>b.addEventListener("click",()=>go(b.dataset.view)));
document.getElementById("darkBtn").addEventListener("click",()=>document.body.classList.toggle("dark"));
render();
